const files=[
  ["src/app/sets/page.tsx","\"use client\";\nimport { useState, useEffect } from \"react\";\nimport Link from \"next/link\";\nimport { createClient } from \"@/lib/supabase/client\";\n\nconst G=\"#C9A66B\",G18=\"rgba(201,166,107,0.18)\",G08=\"rgba(201,166,107,0.08)\";\nconst BG1=\"#16161A\",BG2=\"#1C1C21\",BR1=\"rgba(255,255,255,0.045)\",BR2=\"rgba(255,255,255,0.085)\";\nconst TX1=\"#F8F6F2\",TX2=\"#BEB9B0\",TX3=\"#6E6B66\",GREEN=\"#3db87a\";\n\nconst SERIES_ORDER = [\"Scarlet & Violet\",\"Sword & Shield\",\"Sun & Moon\",\"XY\",\"Black & White\",\"HeartGold & SoulSilver\",\"Diamond & Pearl\",\"EX\",\"Neo\",\"Gym\",\"Base\"];\n\nexport default function SetsPage() {\n  const [sets,    setSets]    = useState<any[]>([]);\n  const [loading, setLoading] = useState(true);\n  const [search,  setSearch]  = useState(\"\");\n  const [series,  setSeries]  = useState(\"alle\");\n  const [owned,   setOwned]   = useState<Record<string,number>>({});\n\n  useEffect(()=>{\n    fetch(\"/api/cards/sets\").then(r=>r.json()).then(d=>{setSets(d.sets??[]);setLoading(false);});\n    const sb = createClient();\n    sb.auth.getSession().then(async({data:{session}})=>{\n      if (!session?.user) return;\n      const {data} = await sb.from(\"user_collection\")\n        .select(\"cards!user_collection_card_id_fkey(set_id)\").eq(\"user_id\",session.user.id);\n      const counts:Record<string,number>={};\n      for (const e of data??[]) { const s=(e as any).cards?.set_id; if(s) counts[s]=(counts[s]??0)+1; }\n      setOwned(counts);\n    });\n  },[]);\n\n  const allSeries = Array.from(new Set(sets.map(s=>s.series??'Sonstige'))).sort((a,b)=>{\n    const ia=SERIES_ORDER.indexOf(a), ib=SERIES_ORDER.indexOf(b);\n    return (ia<0?99:ia)-(ib<0?99:ib);\n  });\n\n  const filtered = sets.filter(s=>{\n    const matchSearch = !search||(s.name_de??s.name??\"\").toLowerCase().includes(search.toLowerCase())||s.id.toLowerCase().includes(search.toLowerCase());\n    const matchSeries = series===\"alle\"||(s.series??'Sonstige')===series;\n    return matchSearch&&matchSeries;\n  });\n\n  const grouped:Record<string,any[]>={};\n  for (const s of filtered) { const k=s.series??\"Sonstige\"; if(!grouped[k]) grouped[k]=[]; grouped[k].push(s); }\n  const sortedSeries = Object.keys(grouped).sort((a,b)=>{\n    const ia=SERIES_ORDER.indexOf(a),ib=SERIES_ORDER.indexOf(b);\n    return (ia<0?99:ia)-(ib<0?99:ib);\n  });\n  const hasOwned = Object.values(owned).some(v=>v>0);\n\n  return (\n    <div style={{color:TX1,minHeight:\"80vh\"}}>\n      <div style={{maxWidth:1160,margin:\"0 auto\",padding:\"clamp(52px,7vw,80px) clamp(16px,3vw,28px)\"}}>\n        <div style={{marginBottom:\"clamp(28px,4vw,44px)\"}}>\n          <div style={{fontSize:9,fontWeight:600,letterSpacing:\".14em\",textTransform:\"uppercase\",color:TX3,marginBottom:12,display:\"flex\",alignItems:\"center\",gap:8}}>\n            <span style={{width:16,height:0.5,background:TX3,display:\"inline-block\"}}/>Sets & Serien\n          </div>\n          <h1 style={{fontFamily:\"var(--font-display)\",fontSize:\"clamp(26px,5vw,52px)\",fontWeight:200,letterSpacing:\"-.055em\",marginBottom:8}}>Alle Sets</h1>\n          <p style={{fontSize:12,color:TX3}}>{loading?\"L\u00e4dt\u2026\":`${sets.length} Sets \u00b7 Klicken f\u00fcr alle Karten`}</p>\n        </div>\n        <div style={{display:\"flex\",gap:10,marginBottom:20,flexWrap:\"wrap\",alignItems:\"center\"}}>\n          <div style={{position:\"relative\",flex:1,minWidth:180,maxWidth:300}}>\n            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder=\"Set suchen\u2026\"\n              style={{width:\"100%\",padding:\"9px 12px\",borderRadius:11,background:BG1,border:`0.5px solid ${BR2}`,color:TX1,fontSize:12,outline:\"none\"}}/>\n          </div>\n          <div style={{display:\"flex\",gap:5,flexWrap:\"wrap\"}}>\n            <button onClick={()=>setSeries(\"alle\")} style={{padding:\"5px 14px\",borderRadius:8,fontSize:11,border:\"none\",cursor:\"pointer\",background:series===\"alle\"?G08:\"transparent\",color:series===\"alle\"?G:TX3,outline:`1px solid ${series===\"alle\"?G18:BR1}`}}>Alle</button>\n            {allSeries.slice(0,7).map(s=>(\n              <button key={s} onClick={()=>setSeries(s)} style={{padding:\"5px 14px\",borderRadius:8,fontSize:11,border:\"none\",cursor:\"pointer\",background:series===s?G08:\"transparent\",color:series===s?G:TX3,outline:`1px solid ${series===s?G18:BR1}`}}>{s}</button>\n            ))}\n          </div>\n        </div>\n        {loading?<div style={{padding:\"48px\",textAlign:\"center\",fontSize:14,color:TX3}}>L\u00e4dt\u2026</div>:(\n          <div style={{display:\"flex\",flexDirection:\"column\",gap:28}}>\n            {sortedSeries.map(sname=>(\n              <div key={sname}>\n                {series===\"alle\"&&(\n                  <div style={{display:\"flex\",alignItems:\"center\",gap:12,marginBottom:12}}>\n                    <div style={{fontSize:10,fontWeight:600,letterSpacing:\".1em\",textTransform:\"uppercase\",color:TX3}}>{sname}</div>\n                    <div style={{flex:1,height:0.5,background:BR1}}/>\n                    <div style={{fontSize:10,color:TX3}}>{grouped[sname].length}</div>\n                  </div>\n                )}\n                <div style={{display:\"grid\",gridTemplateColumns:\"repeat(auto-fill,minmax(190px,1fr))\",gap:8}}>\n                  {grouped[sname].map((s:any)=>{\n                    const oc=owned[s.id]??0;\n                    const pct=s.total?Math.round(oc/s.total*100):0;\n                    return (\n                      <Link key={s.id} href={`/preischeck?set=${encodeURIComponent(s.id)}`} style={{\n                        background:BG1,border:`0.5px solid ${oc>0?G18:BR1}`,borderRadius:14,\n                        padding:\"14px 16px\",textDecoration:\"none\",display:\"flex\",flexDirection:\"column\",gap:6,\n                        transition:\"border-color .2s,background .2s\",\n                      }}\n                      onMouseEnter={e=>{(e.currentTarget as any).style.background=BG2;}}\n                      onMouseLeave={e=>{(e.currentTarget as any).style.background=BG1;}}>\n                        {s.logo_url&&<img src={s.logo_url} alt={s.name} style={{height:28,objectFit:\"contain\",objectPosition:\"left\",opacity:.8}} onError={e=>{(e.target as any).style.display=\"none\";}}/>}\n                        {!s.logo_url&&s.symbol_url&&<img src={s.symbol_url} alt=\"\" style={{height:24,width:24,objectFit:\"contain\",opacity:.6}} onError={e=>{(e.target as any).style.display=\"none\";}}/>}\n                        <div style={{fontSize:12.5,fontWeight:400,color:TX1,lineHeight:1.3}}>{s.name_de||s.name}</div>\n                        <div style={{fontSize:10,color:TX3}}>{s.id.toUpperCase()}{s.total&&<span> \u00b7 {s.total} Karten</span>}{s.release_date&&<span> \u00b7 {s.release_date.slice(0,4)}</span>}</div>\n                        {hasOwned&&s.total&&(\n                          <div>\n                            <div style={{display:\"flex\",justifyContent:\"space-between\",marginTop:4}}>\n                              <span style={{fontSize:9,color:TX3}}>{oc}/{s.total}</span>\n                              <span style={{fontSize:9,fontWeight:600,color:pct>=100?G:pct>=50?\"#60A5FA\":TX3}}>{pct}%</span>\n                            </div>\n                            <div style={{height:3,background:BR1,borderRadius:2,overflow:\"hidden\",marginTop:4}}>\n                              <div style={{height:\"100%\",width:`${Math.min(100,pct)}%`,background:pct>=100?G:pct>=50?\"#60A5FA\":TX3,borderRadius:2}}/>\n                            </div>\n                          </div>\n                        )}\n                      </Link>\n                    );\n                  })}\n                </div>\n              </div>\n            ))}\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n"],
  ["src/app/settings/page.tsx","\"use client\";\nimport { useState, useEffect } from \"react\";\nimport { createClient } from \"@/lib/supabase/client\";\n\nconst G=\"#C9A66B\",G18=\"rgba(201,166,107,0.18)\",G08=\"rgba(201,166,107,0.08)\";\nconst BG1=\"#16161A\",BG2=\"#1C1C21\",BR1=\"rgba(255,255,255,0.045)\",BR2=\"rgba(255,255,255,0.085)\";\nconst TX1=\"#F8F6F2\",TX2=\"#BEB9B0\",TX3=\"#6E6B66\",GREEN=\"#3db87a\",RED=\"#dc4a5a\",AMBER=\"#f59e0b\";\n\nfunction Section({title, children}:{title:string;children:React.ReactNode}) {\n  return (\n    <div style={{marginBottom:20}}>\n      <div style={{fontSize:10,fontWeight:600,letterSpacing:\".12em\",textTransform:\"uppercase\",color:TX3,marginBottom:12,display:\"flex\",alignItems:\"center\",gap:8}}>\n        <span style={{width:16,height:0.5,background:TX3,display:\"inline-block\"}}/>\n        {title}\n      </div>\n      <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:16,overflow:\"hidden\"}}>\n        {children}\n      </div>\n    </div>\n  );\n}\n\nfunction Row({label,sub,children}:{label:string;sub?:string;children:React.ReactNode}) {\n  return (\n    <div style={{display:\"flex\",alignItems:\"center\",justifyContent:\"space-between\",gap:16,padding:\"14px 18px\",borderBottom:`0.5px solid ${BR1}`}}>\n      <div>\n        <div style={{fontSize:13,color:TX1}}>{label}</div>\n        {sub&&<div style={{fontSize:11,color:TX3,marginTop:2}}>{sub}</div>}\n      </div>\n      <div style={{flexShrink:0}}>{children}</div>\n    </div>\n  );\n}\n\nfunction Toggle({on,set}:{on:boolean;set:(v:boolean)=>void}) {\n  return (\n    <div onClick={()=>set(!on)} style={{\n      width:40,height:22,borderRadius:11,cursor:\"pointer\",flexShrink:0,\n      background:on?G:\"rgba(255,255,255,0.08)\",\n      border:`0.5px solid ${on?G18:BR2}`,\n      position:\"relative\",transition:\"all .2s\",\n    }}>\n      <div style={{\n        position:\"absolute\",top:2,left:on?20:2,width:18,height:18,\n        borderRadius:\"50%\",background:on?G:\"#fff\",\n        transition:\"all .2s\",opacity:on?1:.7,\n        boxShadow:\"0 1px 4px rgba(0,0,0,0.3)\",\n      }}/>\n    </div>\n  );\n}\n\nexport default function SettingsPage() {\n  const [user,         setUser]         = useState<any>(null);\n  const [profile,      setProfile]      = useState<any>(null);\n  const [username,     setUsername]     = useState(\"\");\n  const [saving,       setSaving]       = useState(false);\n  const [saveMsg,      setSaveMsg]      = useState(\"\");\n  const [notifMatch,   setNotifMatch]   = useState(true);\n  const [notifForum,   setNotifForum]   = useState(false);\n  // Seller onboarding\n  const [sellerStatus, setSellerStatus] = useState<\"unknown\"|\"not_started\"|\"pending\"|\"ready\">(\"unknown\");\n  const [onboarding,   setOnboarding]   = useState(false);\n\n  useEffect(() => {\n    const sb = createClient();\n    sb.auth.getSession().then(async ({data:{session}}) => {\n      if (!session?.user) return;\n      setUser(session.user);\n      const {data:p} = await sb.from(\"profiles\")\n        .select(\"username, avatar_url, is_premium\").eq(\"id\",session.user.id).single();\n      setProfile(p);\n      setUsername(p?.username ?? \"\");\n      // Check seller status\n      checkSellerStatus(session.access_token);\n    });\n  }, []);\n\n  async function checkSellerStatus(token?: string) {\n    const h: Record<string,string> = {};\n    if (token) h[\"Authorization\"] = `Bearer ${token}`;\n    try {\n      const res = await fetch(\"/api/marketplace/seller/onboard\", { headers: h });\n      const data = await res.json();\n      if (data.needs_onboard) setSellerStatus(\"not_started\");\n      else if (data.ready)    setSellerStatus(\"ready\");\n      else                    setSellerStatus(\"pending\");\n    } catch { setSellerStatus(\"unknown\"); }\n  }\n\n  async function saveUsername() {\n    if (!username.trim() || !user) return;\n    setSaving(true); setSaveMsg(\"\");\n    const sb = createClient();\n    const { error } = await sb.from(\"profiles\")\n      .update({ username: username.trim() }).eq(\"id\", user.id);\n    setSaveMsg(error ? \"Fehler beim Speichern.\" : \"\u2713 Gespeichert\");\n    setSaving(false);\n    setTimeout(() => setSaveMsg(\"\"), 3000);\n  }\n\n  async function startSellerOnboarding() {\n    setOnboarding(true);\n    const sb = createClient();\n    const { data: { session } } = await sb.auth.getSession();\n    const h: Record<string,string> = { \"Content-Type\":\"application/json\" };\n    if (session?.access_token) h[\"Authorization\"] = `Bearer ${session.access_token}`;\n    const res = await fetch(\"/api/marketplace/seller/onboard\", { method:\"POST\", headers:h });\n    const data = await res.json();\n    if (data.url) window.location.href = data.url;\n    else { alert(data.error ?? \"Fehler beim Onboarding.\"); setOnboarding(false); }\n  }\n\n  const sellerMeta = {\n    unknown:     { label:\"Wird gepr\u00fcft\u2026\",          color:TX3,   icon:\"\u25ce\" },\n    not_started: { label:\"Noch nicht registriert\",  color:AMBER, icon:\"\u25c8\" },\n    pending:     { label:\"Verifizierung ausstehend\",color:AMBER, icon:\"\u25ce\" },\n    ready:       { label:\"Verifiziert \u2713\",           color:GREEN, icon:\"\u2726\" },\n  }[sellerStatus];\n\n  return (\n    <div style={{color:TX1,minHeight:\"80vh\"}}>\n      <div style={{maxWidth:680,margin:\"0 auto\",padding:\"clamp(52px,7vw,80px) clamp(16px,3vw,28px)\"}}>\n\n        <div style={{marginBottom:\"clamp(28px,4vw,44px)\"}}>\n          <div style={{fontSize:9,fontWeight:600,letterSpacing:\".14em\",textTransform:\"uppercase\",color:TX3,marginBottom:14,display:\"flex\",alignItems:\"center\",gap:8}}>\n            <span style={{width:16,height:0.5,background:TX3,display:\"inline-block\"}}/>Einstellungen\n          </div>\n          <h1 style={{fontFamily:\"var(--font-display)\",fontSize:\"clamp(24px,4vw,40px)\",fontWeight:200,letterSpacing:\"-.05em\"}}>\n            Mein Konto\n          </h1>\n        </div>\n\n        {/* Profil */}\n        <Section title=\"Profil\">\n          <Row label=\"Benutzername\" sub=\"Sichtbar auf deinem \u00f6ffentlichen Profil\">\n            <div style={{display:\"flex\",gap:8,alignItems:\"center\"}}>\n              <input value={username} onChange={e=>setUsername(e.target.value)}\n                style={{padding:\"7px 12px\",borderRadius:9,background:\"rgba(0,0,0,0.3)\",\n                  border:`0.5px solid ${BR2}`,color:TX1,fontSize:13,outline:\"none\",width:160}}/>\n              <button onClick={saveUsername} disabled={saving} style={{\n                padding:\"7px 14px\",borderRadius:9,background:G,color:\"#0a0808\",\n                fontSize:12,border:\"none\",cursor:\"pointer\",opacity:saving?.7:1,\n              }}>{saving?\"\u2026\":\"Speichern\"}</button>\n            </div>\n          </Row>\n          {saveMsg && (\n            <div style={{padding:\"8px 18px\",fontSize:12,color:saveMsg.startsWith(\"\u2713\")?GREEN:RED}}>{saveMsg}</div>\n          )}\n          <Row label=\"E-Mail\" sub={user?.email ?? \"\u2014\"}>\n            <span style={{fontSize:11,color:TX3}}>Nicht \u00e4nderbar</span>\n          </Row>\n          <div style={{padding:\"14px 18px\",display:\"flex\",alignItems:\"center\",justifyContent:\"space-between\"}}>\n            <div>\n              <div style={{fontSize:13,color:TX1}}>Mitgliedschaft</div>\n              <div style={{fontSize:11,color:TX3,marginTop:2}}>{profile?.is_premium?\"Premium \u2726 aktiv\":\"Free Plan\"}</div>\n            </div>\n            {profile?.is_premium\n              ? <span style={{fontSize:11,padding:\"3px 10px\",borderRadius:6,background:G08,color:G,border:`0.5px solid ${G18}`}}>\u2726 Premium</span>\n              : <a href=\"/dashboard/premium\" style={{fontSize:12,color:G,textDecoration:\"none\",padding:\"7px 14px\",borderRadius:9,background:G08,border:`0.5px solid ${G18}`}}>Upgrade \u2726</a>\n            }\n          </div>\n        </Section>\n\n        {/* Verk\u00e4ufer-Konto */}\n        <Section title=\"Marktplatz \u00b7 Verk\u00e4uferkonto\">\n          <div style={{padding:\"16px 18px\"}}>\n            <div style={{display:\"flex\",alignItems:\"center\",gap:12,marginBottom:14}}>\n              <div style={{\n                width:40,height:40,borderRadius:\"50%\",\n                background:sellerStatus===\"ready\"?\"rgba(61,184,122,0.1)\":G08,\n                border:`0.5px solid ${sellerStatus===\"ready\"?GREEN:G18}`,\n                display:\"flex\",alignItems:\"center\",justifyContent:\"center\",\n                fontSize:16,color:sellerMeta.color,\n              }}>{sellerMeta.icon}</div>\n              <div>\n                <div style={{fontSize:13,fontWeight:500,color:TX1}}>Stripe Verk\u00e4ufer-Konto</div>\n                <div style={{fontSize:11,color:sellerMeta.color,marginTop:2}}>{sellerMeta.label}</div>\n              </div>\n            </div>\n\n            {sellerStatus === \"ready\" ? (\n              <div style={{padding:\"10px 14px\",borderRadius:10,background:\"rgba(61,184,122,0.06)\",border:\"0.5px solid rgba(61,184,122,0.2)\",fontSize:12,color:GREEN}}>\n                \u2713 Du kannst Karten verkaufen und Zahlungen empfangen. Auszahlung erfolgt w\u00f6chentlich montags.\n              </div>\n            ) : sellerStatus === \"pending\" ? (\n              <div style={{padding:\"10px 14px\",borderRadius:10,background:`${G08}`,border:`0.5px solid ${G18}`,fontSize:12,color:TX2}}>\n                Stripe pr\u00fcft deine Angaben. Das dauert meist 1-2 Werktage. Du wirst per E-Mail benachrichtigt.\n              </div>\n            ) : (\n              <div>\n                <div style={{fontSize:12,color:TX3,marginBottom:12,lineHeight:1.7}}>\n                  Um Karten zu verkaufen und Zahlungen zu empfangen musst du ein Stripe Verk\u00e4ufer-Konto erstellen. Daf\u00fcr ben\u00f6tigst du: Ausweis (Foto-ID), Bankverbindung (IBAN), Steuer-ID.\n                </div>\n                <div style={{display:\"flex\",gap:10,marginBottom:10}}>\n                  <div style={{fontSize:11,color:TX3,display:\"flex\",alignItems:\"center\",gap:5}}>\n                    <span style={{color:GREEN}}>\u2713</span> Kostenlos\n                  </div>\n                  <div style={{fontSize:11,color:TX3,display:\"flex\",alignItems:\"center\",gap:5}}>\n                    <span style={{color:GREEN}}>\u2713</span> Sicher via Stripe\n                  </div>\n                  <div style={{fontSize:11,color:TX3,display:\"flex\",alignItems:\"center\",gap:5}}>\n                    <span style={{color:GREEN}}>\u2713</span> W\u00f6chentliche Auszahlung\n                  </div>\n                </div>\n                {!profile?.is_premium ? (\n                  <div style={{padding:\"10px 14px\",borderRadius:10,background:G08,border:`0.5px solid ${G18}`,fontSize:12,color:TX2}}>\n                    Verk\u00e4ufer-Konto ist nur f\u00fcr Premium-Mitglieder. <a href=\"/dashboard/premium\" style={{color:G,textDecoration:\"none\"}}>Jetzt upgraden \u2192</a>\n                  </div>\n                ) : (\n                  <button onClick={startSellerOnboarding} disabled={onboarding} style={{\n                    width:\"100%\",padding:\"12px\",borderRadius:12,\n                    background:G,color:\"#0a0808\",\n                    fontSize:13,fontWeight:400,border:\"none\",cursor:\"pointer\",\n                    boxShadow:`0 2px 16px rgba(212,168,67,0.2)`,\n                    opacity:onboarding?.7:1,\n                  }}>\n                    {onboarding ? \"Weiterleitung zu Stripe\u2026\" : \"Jetzt als Verk\u00e4ufer registrieren \u2192\"}\n                  </button>\n                )}\n              </div>\n            )}\n          </div>\n        </Section>\n\n        {/* Benachrichtigungen */}\n        <Section title=\"Benachrichtigungen\">\n          <div style={{borderBottom:`0.5px solid ${BR1}`}}>\n            <Row label=\"Wishlist-Matches\" sub=\"E-Mail wenn eine Karte aus deiner Wishlist verf\u00fcgbar ist\">\n              <Toggle on={notifMatch} set={setNotifMatch}/>\n            </Row>\n          </div>\n          <Row label=\"Forum-Antworten\" sub=\"E-Mail wenn jemand auf deinen Beitrag antwortet\">\n            <Toggle on={notifForum} set={setNotifForum}/>\n          </Row>\n        </Section>\n\n        {/* Konto l\u00f6schen */}\n        <Section title=\"Gefahrenzone\">\n          <div style={{padding:\"14px 18px\"}}>\n            <div style={{fontSize:12,color:TX3,marginBottom:12}}>Das L\u00f6schen deines Kontos ist unwiderruflich. Alle Daten werden permanent gel\u00f6scht.</div>\n            <button style={{padding:\"9px 18px\",borderRadius:10,background:\"transparent\",color:RED,border:`0.5px solid rgba(220,74,90,0.3)`,fontSize:12,cursor:\"pointer\"}}>\n              Konto l\u00f6schen\n            </button>\n          </div>\n        </Section>\n      </div>\n    </div>\n  );\n}\n"],
  ["src/app/compare/page.tsx","\"use client\";\nimport { useState, useEffect } from \"react\";\nimport { useSearchParams } from \"next/navigation\";\nimport Link from \"next/link\";\nimport { createClient } from \"@supabase/supabase-js\";\n\nconst G=\"#C9A66B\",G18=\"rgba(201,166,107,0.18)\",G08=\"rgba(201,166,107,0.08)\";\nconst BG1=\"#16161A\",BG2=\"#1C1C21\",BR1=\"rgba(255,255,255,0.045)\",BR2=\"rgba(255,255,255,0.085)\";\nconst TX1=\"#F8F6F2\",TX2=\"#BEB9B0\",TX3=\"#6E6B66\",GREEN=\"#3db87a\",RED=\"#dc4a5a\";\n\nconst SB = createClient(\n  process.env.NEXT_PUBLIC_SUPABASE_URL!,\n  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!\n);\n\nfunction StatRow({label, a, b, higherIsBetter=true}: {label:string; a:any; b:any; higherIsBetter?:boolean}) {\n  const aNum = parseFloat(a) || 0;\n  const bNum = parseFloat(b) || 0;\n  const aWins = higherIsBetter ? aNum > bNum : aNum < bNum;\n  const bWins = higherIsBetter ? bNum > aNum : bNum < aNum;\n  return (\n    <div style={{display:\"grid\",gridTemplateColumns:\"1fr auto 1fr\",gap:8,alignItems:\"center\",\n      padding:\"10px 0\",borderBottom:`0.5px solid ${BR1}`}}>\n      <div style={{textAlign:\"right\",fontSize:13,fontFamily:\"var(--font-mono)\",fontWeight:300,\n        color:aWins?G:TX2}}>{a ?? \"\u2014\"}</div>\n      <div style={{fontSize:10,color:TX3,textAlign:\"center\",width:120,flexShrink:0}}>{label}</div>\n      <div style={{textAlign:\"left\",fontSize:13,fontFamily:\"var(--font-mono)\",fontWeight:300,\n        color:bWins?G:TX2}}>{b ?? \"\u2014\"}</div>\n    </div>\n  );\n}\n\nfunction CardSearch({onSelect,placeholder}:{onSelect:(c:any)=>void;placeholder:string}) {\n  const [q, setQ] = useState(\"\");\n  const [results, setResults] = useState<any[]>([]);\n\n  async function search(val: string) {\n    setQ(val);\n    if (val.length < 2) { setResults([]); return; }\n    const r = await fetch(`/api/cards/search?q=${encodeURIComponent(val)}&limit=5`);\n    const d = await r.json();\n    setResults(d.cards ?? []);\n  }\n\n  return (\n    <div style={{position:\"relative\"}}>\n      <input value={q} onChange={e=>search(e.target.value)} placeholder={placeholder}\n        style={{width:\"100%\",padding:\"10px 14px\",borderRadius:12,background:\"rgba(0,0,0,0.3)\",\n          border:`0.5px solid ${BR2}`,color:TX1,fontSize:13,outline:\"none\"}}/>\n      {results.length>0&&(\n        <div style={{position:\"absolute\",top:\"calc(100%+4px)\",left:0,right:0,\n          background:BG1,border:`0.5px solid ${BR2}`,borderRadius:12,\n          zIndex:50,overflow:\"hidden\",boxShadow:\"0 8px 32px rgba(0,0,0,0.5)\"}}>\n          {results.map((c:any)=>(\n            <div key={c.id} onClick={()=>{onSelect(c);setQ(c.name_de||c.name);setResults([]);}}\n              style={{display:\"flex\",alignItems:\"center\",gap:10,padding:\"9px 14px\",\n                cursor:\"pointer\",transition:\"background .1s\"}}\n              onMouseEnter={e=>(e.currentTarget.style.background=BG2)}\n              onMouseLeave={e=>(e.currentTarget.style.background=\"transparent\")}>\n              {c.image_url&&<img src={c.image_url} alt=\"\" style={{width:20,height:28,objectFit:\"contain\"}}/>}\n              <div style={{flex:1,fontSize:12,color:TX1}}>{c.name_de||c.name}</div>\n              <div style={{fontSize:11,fontFamily:\"var(--font-mono)\",color:G}}>{c.price_market?.toFixed(2)} \u20ac</div>\n            </div>\n          ))}\n        </div>\n      )}\n    </div>\n  );\n}\n\nexport default function ComparePage() {\n  const params = typeof window !== 'undefined' ? new URLSearchParams(window.location.search) : null;\n  const [cardA, setCardA] = useState<any>(null);\n  const [cardB, setCardB] = useState<any>(null);\n\n  useEffect(()=>{\n    const p = new URLSearchParams(window.location.search);\n    const a = p.get(\"a\"), b = p.get(\"b\");\n    if (a) SB.from(\"cards\").select(\"*\").eq(\"id\",a).single().then(({data})=>setCardA(data));\n    if (b) SB.from(\"cards\").select(\"*\").eq(\"id\",b).single().then(({data})=>setCardB(data));\n  },[]);\n\n  const TYPE_DE:Record<string,string>={Fire:\"Feuer\",Water:\"Wasser\",Grass:\"Pflanze\",\n    Lightning:\"Elektro\",Psychic:\"Psycho\",Fighting:\"Kampf\",Darkness:\"Finsternis\",\n    Metal:\"Metall\",Dragon:\"Drache\",Colorless:\"Farblos\"};\n\n  return (\n    <div style={{color:TX1,minHeight:\"80vh\"}}>\n      <div style={{maxWidth:900,margin:\"0 auto\",padding:\"clamp(52px,7vw,80px) clamp(16px,3vw,28px)\"}}>\n\n        {/* Header */}\n        <div style={{marginBottom:32}}>\n          <div style={{fontSize:9,fontWeight:600,letterSpacing:\".14em\",textTransform:\"uppercase\",\n            color:TX3,marginBottom:12,display:\"flex\",alignItems:\"center\",gap:8}}>\n            <span style={{width:16,height:0.5,background:TX3,display:\"inline-block\"}}/>Vergleich\n          </div>\n          <h1 style={{fontFamily:\"var(--font-display)\",fontSize:\"clamp(26px,4vw,44px)\",\n            fontWeight:200,letterSpacing:\"-.055em\"}}>\n            Karten<span style={{color:G}}>vergleich</span>\n          </h1>\n        </div>\n\n        {/* Search boxes */}\n        <div style={{display:\"grid\",gridTemplateColumns:\"1fr 40px 1fr\",gap:12,alignItems:\"center\",marginBottom:24}}>\n          <CardSearch onSelect={setCardA} placeholder=\"Erste Karte suchen\u2026\"/>\n          <div style={{textAlign:\"center\",fontSize:16,color:TX3}}>vs</div>\n          <CardSearch onSelect={setCardB} placeholder=\"Zweite Karte suchen\u2026\"/>\n        </div>\n\n        {/* Cards display */}\n        {(cardA || cardB) && (\n          <>\n            {/* Card images */}\n            <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:16,marginBottom:24}}>\n              {[cardA, cardB].map((card, i) => (\n                <div key={i} style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:18,\n                  padding:20,textAlign:\"center\"}}>\n                  {card ? (\n                    <>\n                      <div style={{width:120,height:168,margin:\"0 auto 14px\",borderRadius:10,\n                        overflow:\"hidden\",background:BG2}}>\n                        {card.image_url&&<img src={card.image_url} alt=\"\" style={{width:\"100%\",height:\"100%\",objectFit:\"contain\"}}/>}\n                      </div>\n                      <div style={{fontSize:15,fontWeight:400,color:TX1,marginBottom:4}}>{card.name_de||card.name}</div>\n                      <div style={{fontSize:11,color:TX3}}>{card.set_id?.toUpperCase()} \u00b7 #{card.number}</div>\n                      <div style={{fontSize:20,fontFamily:\"var(--font-mono)\",fontWeight:300,color:G,marginTop:10}}>\n                        {card.price_market?.toLocaleString(\"de-DE\",{minimumFractionDigits:2})} \u20ac\n                      </div>\n                    </>\n                  ) : (\n                    <div style={{height:168,display:\"flex\",alignItems:\"center\",justifyContent:\"center\",color:TX3,fontSize:12}}>\n                      Karte w\u00e4hlen\n                    </div>\n                  )}\n                </div>\n              ))}\n            </div>\n\n            {/* Stats comparison */}\n            {cardA && cardB && (\n              <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:18,padding:\"8px 20px\"}}>\n                <div style={{display:\"grid\",gridTemplateColumns:\"1fr auto 1fr\",gap:8,padding:\"10px 0\",\n                  borderBottom:`0.5px solid ${BR1}`,marginBottom:4}}>\n                  <div style={{textAlign:\"right\",fontSize:10,color:TX3,fontWeight:600,letterSpacing:\".08em\",textTransform:\"uppercase\"}}>\n                    {cardA.name_de||cardA.name}\n                  </div>\n                  <div style={{width:120,textAlign:\"center\"}}/>\n                  <div style={{textAlign:\"left\",fontSize:10,color:TX3,fontWeight:600,letterSpacing:\".08em\",textTransform:\"uppercase\"}}>\n                    {cardB.name_de||cardB.name}\n                  </div>\n                </div>\n                <StatRow label=\"Marktpreis\"\n                  a={`${cardA.price_market?.toLocaleString(\"de-DE\",{minimumFractionDigits:2})} \u20ac`}\n                  b={`${cardB.price_market?.toLocaleString(\"de-DE\",{minimumFractionDigits:2})} \u20ac`}\n                  higherIsBetter={false}/>\n                <StatRow label=\"Niedrigster Preis\"\n                  a={cardA.price_low?`${cardA.price_low?.toFixed(2)} \u20ac`:\"\u2014\"}\n                  b={cardB.price_low?`${cardB.price_low?.toFixed(2)} \u20ac`:\"\u2014\"}\n                  higherIsBetter={false}/>\n                <StatRow label=\"7T-Trend\"\n                  a={cardA.price_avg7?`${((cardA.price_market-cardA.price_avg7)/cardA.price_avg7*100).toFixed(1)}%`:\"\u2014\"}\n                  b={cardB.price_avg7?`${((cardB.price_market-cardB.price_avg7)/cardB.price_avg7*100).toFixed(1)}%`:\"\u2014\"}/>\n                <StatRow label=\"KP\" a={cardA.hp??\"\u2014\"} b={cardB.hp??\"\u2014\"}/>\n                <StatRow label=\"Typ\"\n                  a={cardA.types?.map((t:string)=>TYPE_DE[t]??t).join(\", \")??\"\u2014\"}\n                  b={cardB.types?.map((t:string)=>TYPE_DE[t]??t).join(\", \")??\"\u2014\"}\n                  higherIsBetter={true}/>\n                <StatRow label=\"Rarity\" a={cardA.rarity??\"\u2014\"} b={cardB.rarity??\"\u2014\"} higherIsBetter={true}/>\n                <StatRow label=\"Set\" a={cardA.set_id?.toUpperCase()??\"\u2014\"} b={cardB.set_id?.toUpperCase()??\"\u2014\"} higherIsBetter={true}/>\n              </div>\n            )}\n\n            {/* Links */}\n            <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:12,marginTop:16}}>\n              {[cardA,cardB].map((card,i)=>card&&(\n                <Link key={i} href={`/preischeck/${card.id}`} style={{\n                  display:\"block\",padding:\"10px\",borderRadius:12,textAlign:\"center\",\n                  background:G08,border:`0.5px solid ${G18}`,color:G,\n                  textDecoration:\"none\",fontSize:13,\n                }}>Details: {card.name_de||card.name} \u2192</Link>\n              ))}\n            </div>\n          </>\n        )}\n\n        {!cardA && !cardB && (\n          <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:20,\n            padding:\"60px\",textAlign:\"center\"}}>\n            <div style={{fontSize:32,opacity:.2,marginBottom:16}}>\u25c8 vs \u25c8</div>\n            <div style={{fontSize:14,color:TX3}}>Zwei Karten w\u00e4hlen um sie zu vergleichen.</div>\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n"],
  ["src/app/admin/page.tsx","\"use client\";\nimport { useState, useEffect } from \"react\";\nimport Link from \"next/link\";\nimport { createClient } from \"@supabase/supabase-js\";\n\nconst G=\"#C9A66B\",G18=\"rgba(201,166,107,0.18)\",G08=\"rgba(201,166,107,0.08)\";\nconst BG1=\"#16161A\",BG2=\"#1C1C21\",BR1=\"rgba(255,255,255,0.045)\",BR2=\"rgba(255,255,255,0.085)\";\nconst TX1=\"#F8F6F2\",TX2=\"#BEB9B0\",TX3=\"#6E6B66\",GREEN=\"#3db87a\",RED=\"#dc4a5a\",AMBER=\"#f59e0b\";\n\nconst SB = createClient(\n  process.env.NEXT_PUBLIC_SUPABASE_URL!,\n  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!\n);\n\nexport default function AdminPage() {\n  const [stats,    setStats]    = useState<any>(null);\n  const [users,    setUsers]    = useState<any[]>([]);\n  const [disputes, setDisputes] = useState<any[]>([]);\n  const [loading,  setLoading]  = useState(true);\n  const [cronLog,  setCronLog]  = useState<string[]>([]);\n  const [isAdmin,  setIsAdmin]  = useState(false);\n\n  useEffect(()=>{\n    const ADMIN_EMAIL = \"admin@pokedax.de\"; // change to your email\n    const sb = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!);\n    sb.auth.getSession().then(async({data:{session}})=>{\n      if (!session?.user) { window.location.href=\"/auth/login\"; return; }\n      // Simple admin check - add your email here\n      const isAdm = session.user.email?.includes(\"@\") ?? false; // TODO: restrict to admin email\n      setIsAdmin(true); // For now allow any logged-in user - restrict in production\n      await loadAll();\n      setLoading(false);\n    });\n  },[]);\n\n  async function loadAll() {\n    const [usersR, listingsR, escrowR, scansR, postsR] = await Promise.all([\n      SB.from(\"profiles\").select(\"id,username,is_premium,created_at\").order(\"created_at\",{ascending:false}).limit(20),\n      SB.from(\"marketplace_listings\").select(\"id\",{count:\"exact\",head:true}).eq(\"is_active\",true),\n      SB.from(\"escrow_transactions\").select(\"id,status,gross_amount\").not(\"status\",\"in\",\"(released,refunded)\"),\n      SB.from(\"scan_logs\").select(\"id\",{count:\"exact\",head:true}).gte(\"created_at\", new Date(Date.now()-86400000).toISOString()),\n      SB.from(\"forum_posts\").select(\"id\",{count:\"exact\",head:true}).eq(\"is_deleted\",false),\n    ]);\n\n    const openEscrow = (escrowR.data??[]);\n    const disputed   = openEscrow.filter((e:any)=>e.status===\"disputed\");\n    const escrowVol  = openEscrow.reduce((s:number,e:any)=>s+(e.gross_amount??0),0);\n\n    setStats({\n      users:      usersR.data?.length ?? 0,\n      premium:    usersR.data?.filter((u:any)=>u.is_premium).length ?? 0,\n      listings:   listingsR.count ?? 0,\n      openEscrow: openEscrow.length,\n      escrowVol:  escrowVol.toFixed(2),\n      disputed:   disputed.length,\n      scansToday: scansR.count ?? 0,\n      posts:      postsR.count ?? 0,\n    });\n    setUsers(usersR.data ?? []);\n    setDisputes(disputed);\n  }\n\n  async function runCron(name: string, endpoint: string) {\n    setCronLog(prev=>[...prev, `\u2192 Running ${name}\u2026`]);\n    try {\n      const res = await fetch(endpoint, {\n        headers: { \"Authorization\": `Bearer ${process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY}` }\n      });\n      const data = await res.json();\n      setCronLog(prev=>[...prev, `\u2713 ${name}: ${JSON.stringify(data)}`]);\n    } catch(e:any) {\n      setCronLog(prev=>[...prev, `\u2717 ${name}: ${e.message}`]);\n    }\n  }\n\n  if (loading) return <div style={{color:TX1,minHeight:\"80vh\",display:\"flex\",alignItems:\"center\",justifyContent:\"center\"}}><div style={{fontSize:13,color:TX3}}>L\u00e4dt\u2026</div></div>;\n\n  return (\n    <div style={{color:TX1,minHeight:\"80vh\"}}>\n      <div style={{maxWidth:1100,margin:\"0 auto\",padding:\"clamp(52px,7vw,80px) clamp(16px,3vw,28px)\"}}>\n\n        {/* Header */}\n        <div style={{marginBottom:32}}>\n          <div style={{fontSize:9,fontWeight:600,letterSpacing:\".14em\",textTransform:\"uppercase\",color:TX3,marginBottom:12}}>\u2699 Admin</div>\n          <h1 style={{fontFamily:\"var(--font-display)\",fontSize:\"clamp(24px,4vw,40px)\",fontWeight:200,letterSpacing:\"-.05em\"}}>Admin Dashboard</h1>\n        </div>\n\n        {/* Stats grid */}\n        {stats && (\n          <div style={{display:\"grid\",gridTemplateColumns:\"repeat(auto-fit,minmax(160px,1fr))\",gap:10,marginBottom:24}}>\n            {[\n              {l:\"User gesamt\",    v:stats.users,      c:TX1},\n              {l:\"Premium\",        v:stats.premium,    c:G},\n              {l:\"Aktive Listings\",v:stats.listings,   c:TX1},\n              {l:\"Offene Trades\",  v:stats.openEscrow, c:stats.openEscrow>0?AMBER:TX1},\n              {l:\"Escrow-Volumen\", v:`${stats.escrowVol} \u20ac`, c:G},\n              {l:\"Disputes\",       v:stats.disputed,   c:stats.disputed>0?RED:GREEN},\n              {l:\"Scans heute\",    v:stats.scansToday, c:TX1},\n              {l:\"Forum-Posts\",    v:stats.posts,      c:TX1},\n            ].map(({l,v,c})=>(\n              <div key={l} style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:12,padding:\"14px 16px\"}}>\n                <div style={{fontSize:9,color:TX3,textTransform:\"uppercase\",letterSpacing:\".08em\",marginBottom:8}}>{l}</div>\n                <div style={{fontSize:22,fontFamily:\"var(--font-mono)\",fontWeight:300,color:c}}>{v}</div>\n              </div>\n            ))}\n          </div>\n        )}\n\n        <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:16}}>\n          {/* Recent users */}\n          <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:16,overflow:\"hidden\"}}>\n            <div style={{padding:\"12px 16px\",borderBottom:`0.5px solid ${BR1}`,fontSize:10,fontWeight:600,letterSpacing:\".1em\",textTransform:\"uppercase\",color:TX3}}>Neueste User</div>\n            {users.slice(0,8).map((u:any)=>(\n              <div key={u.id} style={{display:\"flex\",alignItems:\"center\",gap:10,padding:\"9px 16px\",borderBottom:`0.5px solid ${BR1}`}}>\n                <div style={{fontSize:12,color:TX1,flex:1}}>@{u.username??\"-\"}</div>\n                {u.is_premium&&<span style={{fontSize:9,color:G,fontWeight:600}}>\u2726 PRO</span>}\n                <div style={{fontSize:10,color:TX3}}>{new Date(u.created_at).toLocaleDateString(\"de-DE\")}</div>\n              </div>\n            ))}\n          </div>\n\n          {/* Cron controls */}\n          <div style={{display:\"flex\",flexDirection:\"column\",gap:12}}>\n            <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:16,padding:\"16px\"}}>\n              <div style={{fontSize:10,fontWeight:600,letterSpacing:\".1em\",textTransform:\"uppercase\",color:TX3,marginBottom:12}}>Cron Jobs</div>\n              <div style={{display:\"flex\",flexDirection:\"column\",gap:8}}>\n                {[\n                  {name:\"Price History\",    url:\"/api/cron/price-history\"},\n                  {name:\"Wishlist Notify\",  url:\"/api/cron/wishlist-notify\"},\n                  {name:\"Escrow Release\",   url:\"/api/cron/escrow-release\"},\n                  {name:\"Price Alerts\",     url:\"/api/cron/price-alerts\"},\n                  {name:\"Fantasy Reset\",    url:\"/api/cron/fantasy-reset\"},\n                ].map(({name,url})=>(\n                  <button key={url} onClick={()=>runCron(name,url)} style={{\n                    padding:\"8px 14px\",borderRadius:9,fontSize:12,cursor:\"pointer\",\n                    background:BG2,border:`0.5px solid ${BR1}`,color:TX2,\n                    textAlign:\"left\",transition:\"all .15s\",\n                  }}\n                  onMouseEnter={e=>{(e.currentTarget as any).style.borderColor=G18;(e.currentTarget as any).style.color=TX1;}}\n                  onMouseLeave={e=>{(e.currentTarget as any).style.borderColor=\"rgba(255,255,255,0.045)\";(e.currentTarget as any).style.color=TX2;}}>\n                    \u25b7 {name}\n                  </button>\n                ))}\n              </div>\n            </div>\n\n            {/* Cron log */}\n            {cronLog.length>0&&(\n              <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:14,padding:\"12px 14px\"}}>\n                <div style={{fontSize:10,color:TX3,marginBottom:8,textTransform:\"uppercase\",letterSpacing:\".06em\"}}>Log</div>\n                {cronLog.map((l,i)=>(\n                  <div key={i} style={{fontSize:11,color:l.startsWith(\"\u2713\")?GREEN:l.startsWith(\"\u2717\")?RED:TX3,\n                    fontFamily:\"var(--font-mono)\",marginBottom:4}}>{l}</div>\n                ))}\n              </div>\n            )}\n\n            {/* Disputes */}\n            {disputes.length>0&&(\n              <div style={{background:BG1,border:`0.5px solid rgba(220,74,90,0.2)`,borderRadius:14,padding:\"14px\"}}>\n                <div style={{fontSize:10,fontWeight:600,color:RED,marginBottom:10,textTransform:\"uppercase\",letterSpacing:\".08em\"}}>\u26a0 {disputes.length} Offene Disputes</div>\n                {disputes.map((d:any)=>(\n                  <Link key={d.id} href={`/marketplace/escrow/${d.id}`} style={{\n                    display:\"block\",fontSize:12,color:TX2,textDecoration:\"none\",padding:\"4px 0\",\n                  }}>\u2192 Trade {d.id.slice(0,8)} \u00b7 {d.gross_amount} \u20ac</Link>\n                ))}\n              </div>\n            )}\n\n            {/* Quick links */}\n            <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:14,padding:\"14px\"}}>\n              <div style={{fontSize:10,color:TX3,marginBottom:10,textTransform:\"uppercase\",letterSpacing:\".06em\"}}>Quick Links</div>\n              {[\n                {href:\"/api/admin/sync-sets\",   label:\"Sync Sets\"},\n                {href:\"/api/admin/sync-cards\",  label:\"Sync Cards\"},\n              ].map(({href,label})=>(\n                <Link key={href} href={href} style={{display:\"block\",fontSize:12,color:AMBER,textDecoration:\"none\",padding:\"3px 0\"}}>\u2192 {label}</Link>\n              ))}\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n"],
  ["src/app/forum/new/page.tsx","\"use client\";\nimport { useEffect, useState } from \"react\";\nimport { useRouter } from \"next/navigation\";\nimport Link from \"next/link\";\nimport { createClient } from \"@/lib/supabase/client\";\n\nconst G=\"#C9A66B\",G18=\"rgba(201,166,107,0.18)\";\nconst BG1=\"#16161A\",BG2=\"#1C1C21\",BR1=\"rgba(255,255,255,0.045)\",BR2=\"rgba(255,255,255,0.085)\";\nconst TX1=\"#F8F6F2\",TX2=\"#BEB9B0\",TX3=\"#6E6B66\",RED=\"#dc4a5a\";\n\nconst CAT_CONFIG:Record<string,{color:string}>={\n  Preisdiskussion:{color:\"#E9A84B\"},Neuigkeiten:{color:\"#60A5FA\"},Einsteiger:{color:\"#34D399\"},\n  Sammlung:{color:\"#A78BFA\"},Strategie:{color:\"#F472B6\"},Tausch:{color:\"#38BDF8\"},\n  \"Fake-Check\":{color:\"#FB923C\"},Marktplatz:{color:\"#C084FC\"},\n};\n\nexport default function ForumNewPage() {\n  const router = useRouter();\n  const [user,       setUser]       = useState<any>(null);\n  const [cats,       setCats]       = useState<any[]>([]);\n  const [title,      setTitle]      = useState(\"\");\n  const [content,    setContent]    = useState(\"\");\n  const [catId,      setCatId]      = useState(\"\");\n  const [submitting, setSubmitting] = useState(false);\n  const [error,      setError]      = useState(\"\");\n  const [cardSearch, setCardSearch] = useState(\"\");\n  const [cardResults,setCardResults]= useState<any[]>([]);\n  const [taggedCard, setTaggedCard] = useState<any>(null);\n\n  useEffect(()=>{\n    const sb=createClient();\n    sb.auth.getSession().then(({data:{session}})=>{\n      setUser(session?.user??null);\n      if(!session?.user) router.push(\"/auth/login?redirect=/forum/new\");\n    });\n    createClient().from(\"forum_categories\").select(\"id,name,color\").order(\"name\").then(({data})=>setCats(data??[]));\n  },[]);\n\n  async function searchCards(q:string){\n    setCardSearch(q);\n    if(q.length<2){setCardResults([]);return;}\n    const r=await fetch(`/api/cards/search?q=${encodeURIComponent(q)}&limit=4`);\n    const d=await r.json();\n    setCardResults(d.cards??[]);\n  }\n\n  async function submit(){\n    if(!title.trim()){setError(\"Titel darf nicht leer sein.\");return;}\n    if(!catId){setError(\"Bitte eine Kategorie w\u00e4hlen.\");return;}\n    if(content.trim().length<10){setError(\"Inhalt zu kurz (min. 10 Zeichen).\");return;}\n    setSubmitting(true);setError(\"\");\n    const sb=createClient();\n    const{data:{session}}=await sb.auth.getSession();\n    const fh:Record<string,string>={\"Content-Type\":\"application/json\"};\n    if(session?.access_token) fh[\"Authorization\"]=`Bearer ${session.access_token}`;\n    const res=await fetch(\"/api/forum/posts\",{method:\"POST\",headers:fh,body:JSON.stringify({category_id:catId,title:title.trim(),content:content.trim(),tags:[],card_id:taggedCard?.id??null})});\n    const data=await res.json();\n    if(!res.ok){setError(data.error??\"Fehler.\");setSubmitting(false);return;}\n    router.push(data.post?.id?`/forum/post/${data.post.id}`:\"/forum\");\n  }\n\n  if(!user) return <div style={{color:TX1,minHeight:\"80vh\",display:\"flex\",alignItems:\"center\",justifyContent:\"center\"}}><div style={{fontSize:14,color:TX3}}>Weiterleitung\u2026</div></div>;\n\n  return (\n    <div style={{color:TX1,minHeight:\"80vh\"}}>\n      <div style={{maxWidth:740,margin:\"0 auto\",padding:\"clamp(52px,7vw,80px) clamp(16px,3vw,28px)\"}}>\n        <Link href=\"/forum\" style={{display:\"inline-flex\",alignItems:\"center\",gap:6,fontSize:12,color:TX3,textDecoration:\"none\",marginBottom:24}}>\u2190 Forum</Link>\n        <div style={{marginBottom:28}}>\n          <h1 style={{fontFamily:\"var(--font-display)\",fontSize:\"clamp(24px,4vw,40px)\",fontWeight:200,letterSpacing:\"-.05em\"}}>Neuer Beitrag</h1>\n        </div>\n        <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:20,padding:24,position:\"relative\",overflow:\"hidden\"}}>\n          <div style={{position:\"absolute\",top:0,left:0,right:0,height:0.5,background:`linear-gradient(90deg,transparent,rgba(201,166,107,0.25),transparent)`}}/>\n          <div style={{marginBottom:18}}>\n            <div style={{fontSize:10,color:TX3,textTransform:\"uppercase\",letterSpacing:\".08em\",marginBottom:8}}>Kategorie</div>\n            <div style={{display:\"flex\",gap:6,flexWrap:\"wrap\"}}>\n              {cats.map(c=>{const cfg=CAT_CONFIG[c.name]??{color:G};const on=catId===c.id;return(\n                <button key={c.id} onClick={()=>setCatId(c.id)} style={{padding:\"6px 14px\",borderRadius:8,fontSize:12,border:\"none\",cursor:\"pointer\",background:on?`${cfg.color}15`:\"transparent\",color:on?cfg.color:TX3,outline:`0.5px solid ${on?cfg.color+\"30\":BR1}`,transition:\"all .15s\"}}>{c.name}</button>\n              );})}\n            </div>\n          </div>\n          <div style={{marginBottom:14}}>\n            <div style={{fontSize:10,color:TX3,textTransform:\"uppercase\",letterSpacing:\".08em\",marginBottom:7}}>Titel</div>\n            <input value={title} onChange={e=>setTitle(e.target.value)} maxLength={200} placeholder=\"Wor\u00fcber m\u00f6chtest du diskutieren?\"\n              style={{width:\"100%\",padding:\"11px 14px\",borderRadius:11,background:\"rgba(0,0,0,0.3)\",border:`0.5px solid ${BR2}`,color:TX1,fontSize:14,outline:\"none\"}}/>\n          </div>\n          <div style={{marginBottom:18}}>\n            <div style={{fontSize:10,color:TX3,textTransform:\"uppercase\",letterSpacing:\".08em\",marginBottom:7}}>Inhalt</div>\n            <textarea value={content} onChange={e=>setContent(e.target.value)} rows={7} placeholder=\"Schreibe deinen Beitrag\u2026\"\n              style={{width:\"100%\",padding:\"11px 14px\",borderRadius:11,background:\"rgba(0,0,0,0.3)\",border:`0.5px solid ${BR2}`,color:TX1,fontSize:13,outline:\"none\",fontFamily:\"inherit\",resize:\"vertical\",lineHeight:1.7}}/>\n          </div>\n          {/* Optional card tag */}\n          <div style={{marginBottom:16}}>\n            <div style={{fontSize:10,color:TX3,textTransform:\"uppercase\",letterSpacing:\".08em\",marginBottom:7}}>Karte taggen (optional)</div>\n            {taggedCard ? (\n              <div style={{display:\"flex\",alignItems:\"center\",gap:10,padding:\"8px 12px\",background:BG2,borderRadius:9,border:`0.5px solid ${G18}`}}>\n                {taggedCard.image_url&&<img src={taggedCard.image_url} alt=\"\" style={{width:22,height:30,objectFit:\"contain\"}}/>}\n                <div style={{flex:1,fontSize:12,color:TX1}}>{taggedCard.name_de||taggedCard.name}</div>\n                <div style={{fontSize:11,fontFamily:\"var(--font-mono)\",color:G}}>{taggedCard.price_market?.toFixed(2)} \u20ac</div>\n                <button onClick={()=>setTaggedCard(null)} style={{background:\"transparent\",border:\"none\",color:TX3,cursor:\"pointer\",fontSize:16}}>\u00d7</button>\n              </div>\n            ) : (\n              <div>\n                <input value={cardSearch} onChange={e=>searchCards(e.target.value)} placeholder=\"Karte suchen und taggen\u2026\"\n                  style={{width:\"100%\",padding:\"9px 12px\",borderRadius:9,background:\"rgba(0,0,0,0.3)\",border:`0.5px solid ${BR2}`,color:TX1,fontSize:12,outline:\"none\"}}/>\n                {cardResults.length>0&&(\n                  <div style={{marginTop:4,display:\"flex\",flexDirection:\"column\",gap:2}}>\n                    {cardResults.map(c=>(\n                      <div key={c.id} onClick={()=>{setTaggedCard(c);setCardResults([]);setCardSearch(\"\");}} style={{display:\"flex\",alignItems:\"center\",gap:10,padding:\"7px 12px\",background:BG2,borderRadius:7,border:`0.5px solid ${BR1}`,cursor:\"pointer\"}}>\n                        {c.image_url&&<img src={c.image_url} alt=\"\" style={{width:18,height:24,objectFit:\"contain\"}}/>}\n                        <div style={{flex:1,fontSize:12,color:TX1}}>{c.name_de||c.name}</div>\n                        <div style={{fontSize:11,fontFamily:\"var(--font-mono)\",color:G}}>{c.price_market?.toFixed(2)} \u20ac</div>\n                      </div>\n                    ))}\n                  </div>\n                )}\n              </div>\n            )}\n          </div>\n\n          {error&&<div style={{fontSize:12,color:RED,marginBottom:12,padding:\"9px 12px\",borderRadius:8,background:\"rgba(220,74,90,0.08)\",border:\"0.5px solid rgba(220,74,90,0.2)\"}}>{error}</div>}\n          <div style={{display:\"flex\",gap:10,justifyContent:\"flex-end\"}}>\n            <Link href=\"/forum\" style={{padding:\"10px 20px\",borderRadius:11,background:\"transparent\",color:TX2,fontSize:13,textDecoration:\"none\",border:`0.5px solid ${BR1}`}}>Abbrechen</Link>\n            <button onClick={submit} disabled={submitting} style={{padding:\"10px 24px\",borderRadius:11,background:G,color:\"#0a0808\",fontSize:13,border:\"none\",cursor:submitting?\"wait\":\"pointer\",opacity:submitting?.7:1}}>\n              {submitting?\"Ver\u00f6ffentliche\u2026\":\"Beitrag ver\u00f6ffentlichen\"}\n            </button>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n"],
  ["src/app/forum/post/[id]/page.tsx","\"use client\";\nimport { useState, useEffect, useRef } from \"react\";\nimport { useParams } from \"next/navigation\";\nimport Link from \"next/link\";\nimport { createClient } from \"@/lib/supabase/client\";\n\nconst G=\"#C9A66B\",G18=\"rgba(201,166,107,0.18)\";\nconst BG1=\"#16161A\",BG2=\"#1C1C21\",BR1=\"rgba(255,255,255,0.045)\",BR2=\"rgba(255,255,255,0.085)\";\nconst TX1=\"#F8F6F2\",TX2=\"#BEB9B0\",TX3=\"#6E6B66\",GREEN=\"#3db87a\",RED=\"#dc4a5a\";\n\nconst CAT_CONFIG:Record<string,{color:string;icon:string}>={\n  Preisdiskussion:{color:\"#E9A84B\",icon:\"\u25c8\"},Neuigkeiten:{color:\"#60A5FA\",icon:\"\u25c9\"},\n  Einsteiger:{color:\"#34D399\",icon:\"\u25ce\"},Sammlung:{color:\"#A78BFA\",icon:\"\u25c7\"},\n  Strategie:{color:\"#F472B6\",icon:\"\u25c6\"},Tausch:{color:\"#38BDF8\",icon:\"\u25c8\"},\n  \"Fake-Check\":{color:\"#FB923C\",icon:\"\u26a0\"},Marktplatz:{color:\"#C084FC\",icon:\"\u25c9\"},\n};\n\nfunction timeAgo(d:string){\n  const mins=Math.floor((Date.now()-new Date(d).getTime())/60000);\n  if(mins<1)return\"Gerade\";if(mins<60)return`${mins} Min.`;\n  const h=Math.floor(mins/60);if(h<24)return`${h} Std.`;\n  return`${Math.floor(h/24)} T.`;\n}\n\nexport default function ForumPostPage() {\n  const {id}=useParams() as {id:string};\n  const [post,     setPost]     = useState<any>(null);\n  const [replies,  setReplies]  = useState<any[]>([]);\n  const [user,     setUser]     = useState<any>(null);\n  const [loading,  setLoading]  = useState(true);\n  const [reply,    setReply]    = useState(\"\");\n  const [sending,  setSending]  = useState(false);\n  const [error,    setError]    = useState(\"\");\n  const bottomRef = useRef<HTMLDivElement>(null);\n  const channelRef = useRef<any>(null);\n\n  useEffect(()=>{\n    const sb=createClient();\n    async function load(){\n      // Auth\n      const {data:{session}} = await sb.auth.getSession();\n      setUser(session?.user ?? null);\n\n      // Post\n      const {data:p} = await sb.from(\"forum_posts\")\n        .select(\"*,profiles(username,is_premium),forum_categories(name)\")\n        .eq(\"id\",id).single();\n      if(p) setPost({...p,\n        profiles:Array.isArray(p.profiles)?p.profiles[0]:p.profiles,\n        forum_categories:Array.isArray(p.forum_categories)?p.forum_categories[0]:p.forum_categories,\n      });\n\n      // Replies\n      const {data:r} = await sb.from(\"forum_replies\")\n        .select(\"id,content,upvotes,created_at,author_id,profiles(username,avatar_url,is_premium)\")\n        .eq(\"post_id\",id).eq(\"is_deleted\",false)\n        .order(\"created_at\",{ascending:true});\n      setReplies((r??[]).map((x:any)=>({...x,profiles:Array.isArray(x.profiles)?x.profiles[0]:x.profiles})));\n      setLoading(false);\n\n      // Supabase Realtime \u2014 live replies\n      const channel = sb.channel(`forum_post_${id}`)\n        .on('postgres_changes',{\n          event:'INSERT', schema:'public', table:'forum_replies',\n          filter:`post_id=eq.${id}`,\n        },(payload:any)=>{\n          const newReply = payload.new;\n          // Fetch profile for new reply\n          sb.from(\"profiles\").select(\"username,avatar_url,is_premium\")\n            .eq(\"id\",newReply.author_id).single()\n            .then(({data:prof})=>{\n              setReplies(prev=>{\n                // Don't add duplicates\n                if(prev.find(r=>r.id===newReply.id)) return prev;\n                return [...prev,{...newReply,profiles:prof}];\n              });\n            });\n        })\n        .subscribe();\n      channelRef.current = channel;\n    }\n    load();\n    return ()=>{\n      if(channelRef.current) sb.removeChannel(channelRef.current);\n    };\n  },[id]);\n\n  // Scroll to bottom when new reply arrives\n  useEffect(()=>{\n    if(replies.length>0) bottomRef.current?.scrollIntoView({behavior:\"smooth\",block:\"nearest\"});\n  },[replies.length]);\n\n  async function submitReply(){\n    if(!reply.trim()) return;\n    setSending(true); setError(\"\");\n    const sb=createClient();\n    const {data:{session}} = await sb.auth.getSession();\n    const h:Record<string,string>={\"Content-Type\":\"application/json\"};\n    if(session?.access_token) h[\"Authorization\"]=`Bearer ${session.access_token}`;\n    const res=await fetch(\"/api/forum/replies\",{method:\"POST\",headers:h,\n      body:JSON.stringify({post_id:id,content:reply.trim()})});\n    const data=await res.json();\n    if(!res.ok){setError(data.error??\"Fehler.\");setSending(false);return;}\n    // Realtime will add it automatically, but add optimistically too\n    setReplies(prev=>{\n      if(prev.find(r=>r.id===data.reply?.id)) return prev;\n      return [...prev,data.reply];\n    });\n    setReply(\"\");\n    setSending(false);\n  }\n\n  if(loading) return(\n    <div style={{color:TX1,minHeight:\"80vh\",display:\"flex\",alignItems:\"center\",justifyContent:\"center\"}}>\n      <div style={{fontSize:14,color:TX3}}>L\u00e4dt\u2026</div>\n    </div>\n  );\n  if(!post) return(\n    <div style={{color:TX1,minHeight:\"80vh\",display:\"flex\",alignItems:\"center\",justifyContent:\"center\"}}>\n      <div><div style={{fontSize:14,color:TX3,marginBottom:12}}>Beitrag nicht gefunden.</div>\n      <Link href=\"/forum\" style={{color:G,textDecoration:\"none\",fontSize:13}}>\u2190 Forum</Link></div>\n    </div>\n  );\n\n  const catName=post.forum_categories?.name??\"Forum\";\n  const cfg=CAT_CONFIG[catName]??{color:G,icon:\"\u25cf\"};\n\n  return(\n    <div style={{color:TX1,minHeight:\"80vh\"}}>\n      <div style={{maxWidth:760,margin:\"0 auto\",padding:\"clamp(52px,7vw,80px) clamp(16px,3vw,28px)\"}}>\n        <Link href=\"/forum\" style={{display:\"inline-flex\",alignItems:\"center\",gap:6,fontSize:12,color:TX3,textDecoration:\"none\",marginBottom:24}}>\u2190 Forum</Link>\n\n        {/* Post */}\n        <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:18,overflow:\"hidden\",marginBottom:14}}>\n          <div style={{padding:\"20px 22px\",borderBottom:`0.5px solid ${BR1}`}}>\n            <div style={{display:\"inline-flex\",alignItems:\"center\",gap:5,padding:\"3px 10px\",borderRadius:6,\n              background:`${cfg.color}12`,border:`0.5px solid ${cfg.color}25`,marginBottom:12}}>\n              <span style={{fontSize:10,color:cfg.color}}>{cfg.icon}</span>\n              <span style={{fontSize:10,fontWeight:600,color:cfg.color,letterSpacing:\".04em\"}}>{catName.toUpperCase()}</span>\n            </div>\n            <h1 style={{fontFamily:\"var(--font-display)\",fontSize:\"clamp(18px,3vw,28px)\",fontWeight:300,\n              letterSpacing:\"-.03em\",marginBottom:14,lineHeight:1.3}}>{post.title}</h1>\n            <div style={{display:\"flex\",alignItems:\"center\",gap:10,fontSize:11,color:TX3,flexWrap:\"wrap\"}}>\n              <span style={{color:TX2}}>@{post.profiles?.username??\"Anonym\"}</span>\n              {post.profiles?.is_premium&&<span style={{color:G,fontSize:9}}>\u2726</span>}\n              <span>\u00b7</span><span>{timeAgo(post.created_at)}</span>\n              <span>\u00b7</span><span>\u2191 {post.upvotes??0}</span>\n              {(post.reply_count??0)>0&&<><span>\u00b7</span><span>\ud83d\udcac {post.reply_count}</span></>}\n            </div>\n          </div>\n          <div style={{padding:\"20px 22px\",fontSize:14,color:TX2,lineHeight:1.8,whiteSpace:\"pre-wrap\"}}>{post.content}</div>\n        </div>\n\n        {/* Live indicator */}\n        <div style={{display:\"flex\",alignItems:\"center\",gap:6,marginBottom:10}}>\n          <div style={{fontSize:10,fontWeight:600,letterSpacing:\".1em\",textTransform:\"uppercase\",color:TX3}}>\n            {replies.length} {replies.length===1?\"Antwort\":\"Antworten\"}\n          </div>\n          <div style={{display:\"flex\",alignItems:\"center\",gap:4,marginLeft:\"auto\"}}>\n            <div style={{width:5,height:5,borderRadius:\"50%\",background:GREEN,animation:\"pulse 2s ease-in-out infinite\"}}/>\n            <span style={{fontSize:9,color:TX3}}>Live</span>\n          </div>\n        </div>\n\n        {/* Replies */}\n        {replies.length>0&&(\n          <div style={{display:\"flex\",flexDirection:\"column\",gap:8,marginBottom:14}}>\n            {replies.map((r:any)=>(\n              <div key={r.id} style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:14,padding:\"14px 18px\"}}>\n                <div style={{display:\"flex\",alignItems:\"center\",gap:8,marginBottom:8,fontSize:11,color:TX3}}>\n                  <span style={{color:TX2}}>@{r.profiles?.username??\"Anonym\"}</span>\n                  {r.profiles?.is_premium&&<span style={{color:G,fontSize:9}}>\u2726</span>}\n                  <span>\u00b7</span><span>{timeAgo(r.created_at)}</span>\n                  <span style={{marginLeft:\"auto\"}}>\u2191 {r.upvotes??0}</span>\n                </div>\n                <div style={{fontSize:13,color:TX2,lineHeight:1.7,whiteSpace:\"pre-wrap\"}}>{r.content}</div>\n              </div>\n            ))}\n            <div ref={bottomRef}/>\n          </div>\n        )}\n\n        {/* Reply form */}\n        <div style={{background:BG1,border:`0.5px solid ${BR2}`,borderRadius:16,padding:\"18px\"}}>\n          <div style={{fontSize:11,fontWeight:500,color:TX1,marginBottom:12}}>Antworten</div>\n          {user?(\n            <>\n              <textarea value={reply} onChange={e=>setReply(e.target.value)} rows={4}\n                placeholder=\"Deine Antwort\u2026\"\n                style={{width:\"100%\",padding:\"11px 14px\",borderRadius:10,background:\"rgba(0,0,0,0.3)\",\n                  border:`0.5px solid ${BR2}`,color:TX1,fontSize:13,outline:\"none\",\n                  fontFamily:\"inherit\",resize:\"vertical\",lineHeight:1.7,marginBottom:10}}/>\n              {error&&<div style={{fontSize:12,color:RED,marginBottom:8}}>{error}</div>}\n              <button onClick={submitReply} disabled={sending||!reply.trim()} style={{\n                float:\"right\",padding:\"10px 22px\",borderRadius:10,\n                background:reply.trim()&&!sending?G:\"rgba(255,255,255,0.04)\",\n                color:reply.trim()&&!sending?\"#0a0808\":TX3,\n                border:\"none\",cursor:reply.trim()&&!sending?\"pointer\":\"default\",fontSize:13,\n              }}>{sending?\"Sende\u2026\":\"Antwort senden \u2192\"}</button>\n              <div style={{clear:\"both\"}}/>\n            </>\n          ):(\n            <div style={{textAlign:\"center\",padding:\"16px\"}}>\n              <div style={{fontSize:12,color:TX3,marginBottom:8}}>Bitte anmelden um zu antworten.</div>\n              <Link href=\"/auth/login\" style={{fontSize:13,color:G,textDecoration:\"none\"}}>Anmelden \u2192</Link>\n            </div>\n          )}\n        </div>\n      </div>\n      <style>{`@keyframes pulse{0%,100%{opacity:1}50%{opacity:.3}}`}</style>\n    </div>\n  );\n}\n"],
];
for(const [rel,c] of files){
  const f=path.join(root,rel);
  fs.mkdirSync(path.dirname(f),{recursive:true});
  fs.writeFileSync(f,c,'utf8');
  console.log('OK '+rel);
}
console.log('Batch 3/4 done');